## What to do

### src/lib/hyperindex/client.ts
Create a simple GraphQL client for HyperIndex. No need for a heavy library — use fetch:
```ts
const HYPERINDEX_ENDPOINT = 'https://api.hi.gainforest.app/graphql';

export async function queryHyperIndex<T>(query: string, variables?: Record<string, unknown>): Promise<T> {
  const response = await fetch(HYPERINDEX_ENDPOINT, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ query, variables }),
    next: { revalidate: 300 }, // Cache for 5 minutes
  });
  if (!response.ok) throw new Error('HyperIndex query failed: ' + response.statusText);
  const json = await response.json();
  if (json.errors) throw new Error('HyperIndex GraphQL error: ' + JSON.stringify(json.errors));
  return json.data as T;
}
```

