### New behavior
1. After fetching all measured tree occurrences, fetch ALL `app.gainforest.ac.multimedia` records for the org in one paginated pass
2. Index AC records by `occurrenceRef` (AT-URI) → group by `subjectPart`
3. For each measured tree occurrence, look up its AC records by occurrence URI
4. Map `subjectPart` to photo fields:
   - `'entireOrganism'` → `awsUrl` (trunk/whole tree photo)
   - `'leaf'` → `leafAwsUrl`
   - `'bark'` → `barkAwsUrl`
5. Build blob URL from AC record's `file.ref` CID using `buildBlobUrl(PDS_ENDPOINT, did, cid)`

### Implementation details

Add a new type and fetcher:
```ts
const AC_MULTIMEDIA_COLLECTION = 'app.gainforest.ac.multimedia';

type RawMultimediaValue = {
  occurrenceRef?: unknown;
  subjectPart?: unknown;
  file?: { ref?: unknown; mimeType?: string };
  accessUri?: unknown;
  [k: string]: unknown;
};

type RawMultimediaRecord = {
  uri: string;
  cid: string;
  value: RawMultimediaValue;
};

type MultimediaByOccurrence = Map<string, {
  entireOrganism?: string;  // blob URL
  leaf?: string;
  bark?: string;
  flower?: string;
  fruit?: string;
  seed?: string;
  stem?: string;
}>;

const fetchMultimediaIndex = async (did: string): Promise<MultimediaByOccurrence> => {
  const index: MultimediaByOccurrence = new Map();
  let cursor: string | undefined;

  do {
    const response = await ClimateAIAgent.com.atproto.repo.listRecords({
      repo: did,
      collection: AC_MULTIMEDIA_COLLECTION,
      limit: 100,
      cursor,
    });

    const page = response.data.records as RawMultimediaRecord[] | undefined;
    if (page?.length) {
      for (const record of page) {
        const v = record.value;
        const occurrenceRef = typeof v.occurrenceRef === 'string' ? v.occurrenceRef : null;
        if (!occurrenceRef) continue;

        const subjectPart = typeof v.subjectPart === 'string' ? v.subjectPart : null;
        if (!subjectPart) continue;

        const cid = extractCid(v.file?.ref);
        if (!cid) continue;

        const blobUrl = buildBlobUrl(PDS_ENDPOINT, did, cid);
        const existing = index.get(occurrenceRef) ?? {};
        index.set(occurrenceRef, { ...existing, [subjectPart]: blobUrl });
      }
    }

    cursor = response.data.cursor ?? undefined;
  } while (cursor);

  return index;
};
```

