export const useAtprotoStore = create<AtprotoStoreState & AtprotoStoreActions>((set) => ({
  isReady: false,
  auth: { status: "RESUMING", authenticated: false, user: null },

  setAuth: (user) => {
    if (user) {
      set({ isReady: true, auth: { status: "AUTHENTICATED", authenticated: true, user } });
